","new_string":"    // NOTE: we intentionally do NOT rewrite SVGs embedded via <object> to file:///
    // because card JavaScript may need to access `object.contentDocument`, which requires
    // the embedded document to share the same origin as the card (in AnkiDroid this is
    // usually http://127.0.0.1:<port>/).
    // See: https://developer.mozilla.org/en-US/docs/Web/Security/Same-origin_policy
    fun replaceObjectDataWithFileScheme(): Boolean {
        var madeChanges = false
        for (elem in doc.select("object")) {
            val attrValue = elem.attr("data")
            if (attrValue.isEmpty()) continue

            val attrUri = try {
                URI(attrValue)
            } catch (_: URISyntaxException) {
                continue
            }
            if (attrUri.scheme != null) continue

            val type = elem.attr("type").lowercase()
            val pathLower = attrUri.path.lowercase()
            val isSvg = type == "image/svg+xml" || pathLower.endsWith(".svg") || pathLower.endsWith(".svgz")
            if (isSvg) continue

            val path = Paths.get(mediaDir, attrUri.path).toString()
            val newUri = getFileUri(path)

            elem.attr("data", newUri.toString())
            madeChanges = true
        }
        return madeChanges
    }

    val hasMadeChanges =
        replaceWithFileScheme("img", "src") ||
            replaceWithFileScheme("video", "src") ||
            replaceWithFileScheme("audio", "src") ||
            replaceWithFileScheme("source", "src") ||
            replaceObjectDataWithFileScheme()
"}

